oxy_webhelp_navlinks = {"recover_okta_objects-d30753e50513":{"topics":[{"title":"Relationship restore scope","shortdesc":"<p class=\"shortdesc\">Granular recovery for Okta objects enables you to restore selected objects along with         their dependencies. <span class=\"ph\">RSC<\/span> provides options to recover selected objects,         interconnected objects, and their relationships. This feature enables you to re-establish         broken links and corrupted relationships, such as those between users and         groups.<\/p>","href":"okta\/relationship_restore_scope.html","attributes":{"data-id":"relationship_restore_scope"},"menu":{"hasChildren":false},"tocID":"relationship_restore_scope-d30753e50526","topics":[]},{"title":"Recreate objects and restore relationships","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> enhances granular recovery of critical Okta objects by         discovering, displaying, and simplifying the complex, interlinked object structure and         dependencies in Okta. This enables you to precisely select and manage the recovery of         critical Okta objects and their associated dependencies.<\/p>","href":"okta\/recreate_objects_restore_relationships.html","attributes":{"data-id":"recreate_objects_restore_relationships"},"menu":{"hasChildren":false},"tocID":"recreate_objects_restore_relationships-d30753e50540","topics":[]},{"title":"Multi-valued data recovery rules","shortdesc":"<p class=\"shortdesc\">Information about how to handle conflicts for multi-valued data, both attributes and         relationships, during recovery. <span class=\"ph\">RSC<\/span> provides two options, overwrite or merge         values, enabling you to select the option that best meets your organizational requirements         for data consistency.<\/p>","href":"okta\/multivalued_data_recovery_rules.html","attributes":{"data-id":"multivalued_data_recovery_rules"},"menu":{"hasChildren":false},"tocID":"multivalued_data_recovery_rules-d30753e50553","topics":[]},{"title":"User status recovery rules","shortdesc":"<p class=\"shortdesc\">Information about how <span class=\"ph\">RSC<\/span> recovers users that were in a Staged or         Locked Out status when the snapshot was taken. Okta does not support reverting user         statuses, so <span class=\"ph\">RSC<\/span> provides settings to control how it restores user         statuses.<\/p>","href":"okta\/user_status_recovery_rules.html","attributes":{"data-id":"user_status_recovery_rules"},"menu":{"hasChildren":false},"tocID":"user_status_recovery_rules-d30753e50567","topics":[]},{"title":"Okta group rules recovery","shortdesc":"<p class=\"shortdesc\">To recover a group rule, it is important to understand that an Okta group rule cannot         exist without its target groups. <span class=\"ph\">RSC<\/span> applies dependency-aware behavior when         recovering group rules.<\/p>","href":"okta\/okta_group_rules_recovery.html","attributes":{"data-id":"okta_group_rules_recovery"},"menu":{"hasChildren":false},"tocID":"okta_group_rules_recovery-d30753e50584","topics":[]},{"title":"Recovering Okta objects","shortdesc":"<p class=\"shortdesc\">Recover required Okta objects using automated or on-demand snapshots of your Okta         tenant when a critical object is accidentally deleted or changed.<\/p>","href":"okta\/recovering_okta_objects.html","attributes":{"data-id":"recovering_okta_objects"},"menu":{"hasChildren":false},"tocID":"recovering_okta_objects-d30753e50598","topics":[]}]}};